// Step 1: Safely get raw text input from 'output' field
let rawOutput = $input.first().json.output;

if (typeof rawOutput !== 'string') {
  try {
    rawOutput = JSON.stringify(rawOutput);
  } catch (e) {
    rawOutput = "";
  }
}

const text = rawOutput.toLowerCase();

// Step 2: Keyword banks (extended)
const deceptiveKeywords = [
  // Existing keywords
  "quick money", "work from home and earn", "investment required", "guaranteed income",
  "no experience needed", "limited seats", "act now", "urgent requirement", "100% payout",
  "training fee", "processing charge", "registration fee", "pay to apply", "sms sending job",
  "ad posting job", "captcha typing", "easy income", "double your salary", "government approved",
  "make money fast", "no interview required", "instant job", "just 2 hours a day", "click now",
  "join immediately", "minimal effort", "bulk hiring", "get rich quick", "foreign job offer",

  // 💸 Financial red flags
  "payment", "₹", "rs.", "rupee", "security deposit", "bank account",
  "account number", "bank transfer", "paytm", "google pay", "phonepe", "send money", 
  "transfer fee", "non-refundable fee"
];

const generalJobKeywords = [
  "job title", "salary", "location", "experience", "skills", "responsibilities", "benefits",
  "qualifications", "requirements", "interview", "position", "company", "full-time", "part-time",
  "remote", "on-site", "job description", "apply", "deadline", "role", "vacancy", "department",
  "internship", "stipend", "team", "manager", "technical", "non-technical", "education"
];

// Step 3: Keyword matching
function extractMatches(list, input) {
  return list.filter(phrase => new RegExp(`\\b${phrase.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, "gi").test(input));
}

const foundDeceptive = extractMatches(deceptiveKeywords, text);
const foundGeneral = extractMatches(generalJobKeywords, text);

// Step 4: Scoring
const maxDeceptiveWeight = 10;
let rawScore = foundDeceptive.length * 2 - foundGeneral.length * 0.5;
let score = Math.min(maxDeceptiveWeight, Math.max(0, Math.round(rawScore)));

let verdict;
if (score >= 7) verdict = "Fake";
else if (score >= 4) verdict = "Suspicious";
else verdict = "Genuine";

// Step 5: Risk explanation summary
let summary = `✅ Found ${foundGeneral.length} general job-related keywords.\n`;
summary += `⚠️ Found ${foundDeceptive.length} potentially deceptive indicators.\n`;

if (foundDeceptive.length > 0) {
  summary += `🔍 Deceptive terms detected: ${foundDeceptive.join(", ")}.\n`;
}

summary += `\n📊 Deception Score: ${score}/10 → Verdict: **${verdict}**.`;

// Step 6: Output
return [
  {
    json: {
      preview: text.slice(0, 300) + (text.length > 300 ? "... (truncated)" : ""),
      matched_deceptive_keywords: foundDeceptive,
      matched_general_keywords: foundGeneral,
      count_deceptive: foundDeceptive.length,
      count_general: foundGeneral.length,
      deception_score: score,
      verdict: verdict,
      summary: summary.trim()
    }
  }
];

// Get the website from input safely
let website = $input.first().json.output?.Website || "";

// Ensure it's a string
if (typeof website !== "string") {
  website = String(website || "");
}

// Trim and normalize
website = website.trim();

// Output just the cleaned website link
return [{ json: { website } }];

// Step 1: Get and sanitize input
let raw = $input.first()?.json?.text ?? "";

if (typeof raw !== 'string') {
  try {
    raw = JSON.stringify(raw);
  } catch {
    raw = "";
  }
}

const text = raw.toLowerCase().replace(/\s+/g, " ").trim();

// Step 2: Expanded keyword and phrase banks

// 🧨 Financial or payment-related scams
const paymentScams = [
  "registration fee", "processing fee", "security deposit", "training fee",
  "application charge", "deposit", "pay to apply", "payable amount",
  "registration charges", "refundable fee", "service charge", "gst included",
  "bank transfer", "payment methods", "send money", "transfer amount",
  "gpay", "paytm", "phonepe", "upi id", "account number"
];

// 💰 Unrealistic earning / bait offers
const moneyBait = [
  "guaranteed income", "earn money", "get rich", "quick money", "easy income",
  "no experience needed", "work from home", "earn ₹", "instant job",
  "limited seats", "act now", "apply fast", "urgent requirement"
];

// 📢 HR / fake authority triggers
const fakeAuthority = [
  "dear intern", "dear candidate", "hr department", "authorized recruiter",
  "official partner", "verified by", "approved by", "offer letter after payment",
  "internship confirmation", "your profile has been shortlisted"
];

// 🧠 Legitimate job signals (to reduce false positives)
const legitIndicators = [
  "position", "company", "experience", "skills", "responsibilities", "location",
  "salary", "requirements", "team", "manager", "vacancy", "full-time", "part-time",
  "official website", "career page", "linkedIn", "email id", "remote"
];

// Step 3: Pattern matching helper
const matchCount = (keywords, input) => {
  const matches = keywords.filter(k => input.includes(k));
  return { matches, count: matches.length };
};

const payment = matchCount(paymentScams, text);
const bait = matchCount(moneyBait, text);
const authority = matchCount(fakeAuthority, text);
const legit = matchCount(legitIndicators, text);

// Step 4: Score calculation
let score = 0;
score += payment.count * 2.5;
score += bait.count * 1.5;
score += authority.count * 1.2;
score -= legit.count * 0.5;

// Extra penalties for suspicious patterns
if (text.includes("offer letter") && text.includes("payment")) score += 3;
if (text.includes("internship") && text.includes("fee")) score += 2.5;
if (text.includes("secure your spot")) score += 2;
if (text.match(/\bby \d{1,2}[-/]\d{1,2}[-/]\d{2,4}\b/)) score += 1.5; // deadlines
if (text.match(/\₹\s?\d+/)) score += 1.5; // currency mention

// Step 5: Regex-based detections
const currency = [...text.matchAll(/(?:₹|rs\.?|rupees?|usd|inr)\s?[\d,.]+/g)].map(m => m[0]);
const links = [...text.matchAll(/\bhttps?:\/\/[^\s]+/g)].map(m => m[0]);
const emails = [...text.matchAll(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g)].map(m => m[0]);

// Step 6: Final verdict thresholds
let verdict = "Genuine";
if (score >= 8) verdict = "Fake";
else if (score >= 4) verdict = "Suspicious";

// Step 7: Output formatted JSON
return [
  {
    json: {
      preview: text.slice(0, 350) + (text.length > 350 ? "..." : ""),
      deception_score: Math.round(score * 10) / 10,
      verdict: verdict,
      matched_payment_keywords: payment.matches,
      matched_bait_keywords: bait.matches,
      matched_authority_keywords: authority.matches,
      matched_legit_keywords: legit.matches,
      currency_mentions: currency,
      email_addresses: emails,
      external_links: links,
      summary_flags: [
        ...(currency.length ? ["Currency Mention"] : []),
        ...(emails.length ? ["Email Mention"] : []),
        ...(links.length ? ["External Link"] : []),
        ...(text.includes("offer letter") && text.includes("payment") ? ["Offer After Payment"] : [])
      ]
    }
  }
];

const verdict = $json.verdict;
const prob = $json.probability;

if (verdict === "Fake" && prob > 0.8) {
  return [{ alert: "Scam job detected!", confidence: prob }];
} else {
  return [{ alert: "Looks fine", confidence: prob }];
}

// --- Step 1: Get inputs ---
const heuristic = $input.all()[0]?.json || {}; // From heuristic node
const ml = $input.all()[1]?.json || {};        // From FastAPI ML model

const heuristicScore = heuristic.deception_score ?? 0;
const mlProb = ml.probability ?? 0;
const mlVerdict = ml.verdict ?? (mlProb > 0.6 ? "Fake" : "Genuine");

// --- Step 2: Weighted hybrid score ---
const hybridScore = (heuristicScore / 10) * 0.4 + mlProb * 0.6;
const hybridPercent = Math.round(hybridScore * 1000) / 10; // e.g. 78.3%

let hybridVerdict = "Genuine";
if (hybridScore >= 0.75) hybridVerdict = "Fake";
else if (hybridScore >= 0.45) hybridVerdict = "Suspicious";

// --- Step 3: Compose detailed reasoning ---
const reasons = [];
const emailCount = heuristic.email_addresses?.length || 0;
const linkCount = heuristic.external_links?.length || 0;
const currencyCount = heuristic.currency_mentions?.length || 0;
const paymentTerms = heuristic.matched_payment_keywords || [];
const baitTerms = heuristic.matched_bait_keywords || [];
const authorityTerms = heuristic.matched_authority_keywords || [];

if (mlProb >= 0.8) {
  reasons.push(
    `The AI model predicted a ${Math.round(mlProb * 100)}% probability that the posting is deceptive, which strongly influences the overall verdict.`
  );
} else if (mlProb >= 0.6) {
  reasons.push(
    `The machine learning model indicates a moderately high probability (${Math.round(mlProb * 100)}%) of deception.`
  );
} else {
  reasons.push(
    `The AI model detected minimal statistical signals of deception in the text.`
  );
}

if (heuristicScore >= 8) {
  reasons.push(
    `Heuristic analysis flagged numerous high-risk keywords and scam patterns (e.g. ${[...paymentTerms, ...baitTerms, ...authorityTerms].slice(0, 3).join(", ")}). This suggests strong linguistic signs of fraudulent intent.`
  );
} else if (heuristicScore >= 5) {
  reasons.push(
    `Heuristic analysis found several moderate-risk terms commonly used in misleading job ads, though not enough for a full fraud determination.`
  );
} else {
  reasons.push(
    `The heuristic keyword analysis revealed few or no deceptive terms.`
  );
}

if (currencyCount > 0) {
  reasons.push(
    `Currency references were detected (${heuristic.currency_mentions.join(", ")}), which often indicates payment requests or financial commitments — a major red flag in job listings.`
  );
}

if (emailCount > 1) {
  reasons.push(
    `${emailCount} different email addresses were found (${heuristic.email_addresses.slice(0, 3).join(", ")}), suggesting potential impersonation or unverified HR communication channels.`
  );
}

if (linkCount > 0) {
  reasons.push(
    `${linkCount} external link${linkCount > 1 ? "s" : ""} were included (${heuristic.external_links.slice(0, 2).join(", ")}). Legitimate employers rarely use public forms or anonymous links for recruitment, which strengthens suspicion.`
  );
}

if (hybridVerdict === "Fake") {
  reasons.push(
    `Combining both AI and rule-based results, the posting clearly exhibits multiple fraud indicators — especially payment instructions and non-official contact channels.`
  );
} else if (hybridVerdict === "Suspicious") {
  reasons.push(
    `Some evidence of deceptive phrasing was detected, though not conclusively fraudulent. The message should be verified manually before taking action.`
  );
} else {
  reasons.push(
    `Both AI and heuristic systems found minimal signs of fraud. The posting appears legitimate but still warrants a quick authenticity check.`
  );
}

// --- Step 4: Build narrative summary ---
const summary = `
🤖 Hybrid Deception Analysis
────────────────────────────
Verdict: ${hybridVerdict}
AI Model Probability: ${(mlProb * 100).toFixed(1)}%
Heuristic Score: ${heuristicScore}/10
Hybrid Confidence: ${hybridPercent}%

🧩 Reasoning:
${reasons.map((r, i) => `${i + 1}. ${r}`).join("\n")}

⚠️ Overall Assessment:
${hybridVerdict === "Fake"
  ? "This posting exhibits strong signals of fraud, combining linguistic red flags, financial demands, and statistical anomalies from the model."
  : hybridVerdict === "Suspicious"
  ? "Moderate deception cues detected. Proceed cautiously and validate sender credentials before engagement."
  : "No critical red flags detected. The posting appears legitimate, but basic due diligence is advised."}
`.trim();

// --- Step 5: Output structured result ---
return [
  {
    json: {
      ml_probability: mlProb,
      ml_verdict: mlVerdict,
      heuristic_score: heuristicScore,
      hybrid_confidence: hybridPercent,
      verdict: hybridVerdict,
      reasoning: reasons,
      summary
    }
  }
];

const data = $input.first()?.json ?? {};

const {
  verdict = "Unknown",
  deception_score = 0,
  currency_mentions = [],
  email_addresses = [],
  external_links = [],
  summary_flags = [],
  matched_payment_keywords = [],
  matched_bait_keywords = [],
  matched_authority_keywords = []
} = data;

// --- Helper: Shorten long URLs & emails for readability
const short = (arr, max = 3) =>
  arr.length > max ? arr.slice(0, max).concat("...") : arr;

// --- Build key highlights ---
const keyHighlights = [];

if (matched_payment_keywords.length) keyHighlights.push("payment-related terms");
if (matched_bait_keywords.length) keyHighlights.push("bait/offer language");
if (matched_authority_keywords.length) keyHighlights.push("fake HR authority words");
if (currency_mentions.length) keyHighlights.push("currency mention");
if (external_links.length) keyHighlights.push("external link");
if (email_addresses.length > 2) keyHighlights.push("multiple HR emails");

const highlightText = keyHighlights.length
  ? keyHighlights.join(", ")
  : "no major suspicious terms";

// --- Risk level summary ---
const riskLevel =
  deception_score >= 8 ? "High" : deception_score >= 4 ? "Medium" : "Low";

// --- Construct crisp summary ---
const summary = `
 Verdict: ${verdict} (Score: ${deception_score}, Risk: ${riskLevel})
 Key Signs: ${highlightText}.
 Emails: ${short(email_addresses).join(", ") || "None"}
 Currency: ${currency_mentions.join(", ") || "None"}
 Links: ${short(external_links).join(", ") || "None"}
 Red Flags: ${summary_flags.join(", ") || "None"}
 `.trim();

// --- Output ---
return [
  {
    json: {
      verdict,
      deception_score,
      risk_level: riskLevel,
      summary
    }
  }
];

// === INPUT HANDLING ===
const heuristic = $input.all()[0]?.json || {};  // From Heuristic Node
const ml = $input.all()[1]?.json || {};         // From FastAPI ML Node
const mistral = $input.all()[2]?.json || {};    // From Mistral Node

// === EXTRACT VALUES ===
const heuristicScore = heuristic.deception_score ?? 0;
const heuristicVerdict =
  heuristic.verdict ?? (heuristicScore >= 6 ? "Fake" : heuristicScore >= 3 ? "Suspicious" : "Genuine");

const mlProb = ml.probability ?? 0;
const mlVerdict = ml.verdict ?? (mlProb > 0.6 ? "Fake" : mlProb > 0.4 ? "Suspicious" : "Genuine");

const mistralVerdict = mistral.verdict ?? "Unknown";
const mistralConfidence = mistral.confidence ?? 0.5;

// === WEIGHTED HYBRID SCORING ===
const hybridScore =
  (heuristicScore / 10) * 0.3 + // heuristic weight
  mlProb * 0.4 +                // model weight
  mistralConfidence * 0.3;      // Mistral AI weight

const hybridPercent = Math.round(hybridScore * 1000) / 10;

let finalVerdict = "Genuine";
if (hybridScore >= 0.75) finalVerdict = "Fake";
else if (hybridScore >= 0.45) finalVerdict = "Suspicious";

// === DETAILED REASONING SECTION ===
const reasons = [];

// Machine Learning Model contribution
if (mlProb >= 0.8) {
  reasons.push(
    `🧮 The ML model predicted a ${Math.round(mlProb * 100)}% probability of fraud, classifying the posting as **${mlVerdict}**. This strongly influences the final decision.`
  );
} else if (mlProb >= 0.6) {
  reasons.push(
    `📈 The ML model shows a moderate likelihood (${Math.round(mlProb * 100)}%) of deception, labeling it as **${mlVerdict}**.`
  );
} else {
  reasons.push(
    `📊 The ML model found minimal statistical evidence of deception and classified the posting as **${mlVerdict}**.`
  );
}

// Heuristic contribution
if (heuristicScore >= 8) {
  reasons.push(
    `🔍 The heuristic engine detected multiple strong red flags (keywords such as ${heuristic.matched_deceptive_keywords?.slice(0, 3).join(", ") || "payment-related terms"}), assigning a verdict of **${heuristicVerdict}**.`
  );
} else if (heuristicScore >= 5) {
  reasons.push(
    `🧠 The heuristic system found several moderate-risk terms typically linked to fake postings and marked it as **${heuristicVerdict}**.`
  );
} else {
  reasons.push(
    `✅ The heuristic rules found few or no suspicious keywords and rated this as **${heuristicVerdict}**.`
  );
}

// Mistral contribution
if (mistralVerdict && mistralVerdict !== "Unknown") {
  reasons.push(
    `🗣️ The Mistral LLM analyzed the text contextually and concluded the posting is **${mistralVerdict}**, with ${(mistralConfidence * 100).toFixed(1)}% confidence.`
  );
  if (mistral.feedback) {
    reasons.push(`💬 AI Feedback: ${mistral.feedback}`);
  }
}

// === VERDICT ALIGNMENT COMMENTARY ===
let alignmentNote = "";
const verdicts = [heuristicVerdict, mlVerdict, mistralVerdict];
const uniqueVerdicts = [...new Set(verdicts.filter(v => v !== "Unknown"))];

if (uniqueVerdicts.length === 1) {
  alignmentNote = `🟢 All three systems are in **complete agreement** — the posting is confidently classified as **${uniqueVerdicts[0]}**.`;
} else if (uniqueVerdicts.length === 2) {
  alignmentNote = `🟠 Two systems agree (${uniqueVerdicts.join(" & ")}) while one differs. The disagreement indicates borderline features requiring closer review.`;
} else {
  alignmentNote = `🔴 All three systems differ slightly in classification, which suggests the posting contains both genuine and deceptive language patterns.`;
}

// === FINAL NARRATIVE SUMMARY ===
const summary = `
🤖 AI Fraud Investigator Report
────────────────────────────
🧾 Final Verdict: ${finalVerdict}
🎯 Confidence: ${hybridPercent}%

📊 Individual Verdicts:
- ML Model → ${mlVerdict} (${(mlProb * 100).toFixed(1)}%)
- Heuristic Engine → ${heuristicVerdict} (Score: ${heuristicScore}/10)
- Mistral LLM → ${mistralVerdict} (${(mistralConfidence * 100).toFixed(1)}%)

────────────────────────────
🧩 Analytical Breakdown:
${reasons.map((r, i) => `${i + 1}. ${r}`).join("\n")}

${alignmentNote}

⚠️ Final Assessment:
${
  finalVerdict === "Fake"
    ? "🚨 The posting shows multiple overlapping fraud indicators across all detection layers. It is strongly recommended to avoid engagement, do not send payments, and verify company authenticity."
    : finalVerdict === "Suspicious"
    ? "⚠️ Mixed signals detected. The posting may have some legitimate traits but also deceptive patterns. Verification of sender identity and job legitimacy is advised."
    : "✅ The posting appears legitimate, with all systems showing low deception probability. Still, maintain general caution when sharing personal details online."
}
`.trim();

// === OUTPUT FINAL RESULT ===
return [
  {
    json: {
      final_verdict: finalVerdict,
      heuristic_confidence_percent: hybridPercent,
      ml_verdict: "Suspicious",
      mistral_confidence: mistralConfidence,
      rulebased_verdict: heuristicVerdict,
      rulebased_score: heuristicScore,
      reasoning_summary: reasons,
      alignment_summary: alignmentNote,
      final_report: summary
    }
  }
];
